11	// RunnerDockerImage is the container image used for docker-mode runners.
12	const RunnerDockerImage = "ghcr.io/actions/actions-runner:latest"
13	
14	// dockerRunnerEntryScript registers once (registration tokens are single-use) then runs the
15	// listener. Official ghcr.io/actions/actions-runner has no CMD; it expects config.sh then run.sh.
16	const dockerRunnerEntryScript = `cd /home/runner && if [ ! -f .runner ]; then ./config.sh --unattended --replace; fi && exec ./run.sh`
17	
18	// ContainerName returns the Docker container name for a runner instance.
19	func ContainerName(instanceName string) string {
20		return "gh-runner-" + instanceName
21	}
22	
23	func containerName(instanceName string) string {
24		return ContainerName(instanceName)
25	}
26	
27	// shellSingleQuote wraps s in single quotes for a POSIX shell word (safe for docker -e on Linux/macOS SSH).
28	func shellSingleQuote(s string) string {
29		return "'" + strings.ReplaceAll(s, "'", "'\\''") + "'"
30	}
31	
32	// dockerEnvFlag renders one -e flag as a single shell word: -e 'NAME=value'
33	func dockerEnvFlag(name, value string) string {
34		return "-e " + shellSingleQuote(name+"="+value)
35	}
36	
37	// dockerCapAddFlags renders zero or more --cap-add flags for docker run (Linux capability names, e.g. NET_ADMIN).
38	func dockerCapAddFlags(capAdds []string) string {
39		if len(capAdds) == 0 {
40			return ""
41		}
42		var b strings.Builder
43		for _, c := range capAdds {
44			c = strings.TrimSpace(c)
45			if c == "" {
46				continue
47			}
48			fmt.Fprintf(&b, "--cap-add %s ", c)
49		}
50		return b.String()
51	}
52	
53	type dockerStartOpts struct {
54		ContainerName string
55		InstanceName  string
56		RegToken      string
57		RepoURL       string
58		Labels        string
59		SockMount     string
60		Image         string
61		NetworkMode   string
62		CapAdds       []string
63		RunnerGroup   string
64		Ephemeral     bool
65	}
66	
67	func dockerStartCommand(opts dockerStartOpts) string {
68		var b strings.Builder
69		fmt.Fprintf(&b, "docker run -d --name %s ", opts.ContainerName)
70		if strings.TrimSpace(opts.NetworkMode) == "host" {
71			b.WriteString("--network host ")
72		}
73		restartPolicy := "unless-stopped"
74		if opts.Ephemeral {
75			restartPolicy = "no"
76		}
77		fmt.Fprintf(&b, "--restart %s ", restartPolicy)
78		b.WriteString(dockerCapAddFlags(opts.CapAdds))
79		b.WriteString(dockerEnvFlag("ACTIONS_RUNNER_INPUT_URL", opts.RepoURL))
80		b.WriteByte(' ')
81		b.WriteString(dockerEnvFlag("ACTIONS_RUNNER_INPUT_TOKEN", opts.RegToken))
82		b.WriteByte(' ')
83		b.WriteString(dockerEnvFlag("ACTIONS_RUNNER_INPUT_NAME", opts.InstanceName))
84		b.WriteByte(' ')
85		b.WriteString(dockerEnvFlag("ACTIONS_RUNNER_INPUT_LABELS", opts.Labels))
86		b.WriteByte(' ')
87		b.WriteString(dockerEnvFlag("ACTIONS_RUNNER_INPUT_WORK", "_work"))
88		b.WriteByte(' ')
89		if opts.RunnerGroup != "" {
90			b.WriteString(dockerEnvFlag("ACTIONS_RUNNER_INPUT_RUNNERGROUP", opts.RunnerGroup))
91			b.WriteByte(' ')
92		}
93		if opts.Ephemeral {
94			b.WriteString(dockerEnvFlag("ACTIONS_RUNNER_INPUT_EPHEMERAL", "true"))
95			b.WriteByte(' ')
96		}
97		if s := strings.TrimSpace(opts.SockMount); s != "" {
98			b.WriteString(s)
99			b.WriteByte(' ')
100		}
101		b.WriteString("--entrypoint /bin/bash ")
102		b.WriteString(opts.Image)
103		b.WriteString(" -c ")
104		b.WriteString(shellSingleQuote(dockerRunnerEntryScript))
105		return b.String()
106	}
