380	// UnixDockerCLIInstalled reports whether a docker binary exists on PATH on the host.
381	func UnixDockerCLIInstalled(h *host.Host) (bool, error) {
382		out, err := h.Run(prependDarwinDockerPATH(h, `if command -v docker >/dev/null 2>&1; then echo yes; else echo no; fi`))
383		if err != nil {
384			return false, err
385		}
386		switch strings.TrimSpace(out) {
387		case "yes":
388			return true, nil
389		case "no":
390			return false, nil
391		default:
392			return false, fmt.Errorf("unexpected output checking docker CLI: %q", out)
393		}
394	}
395	
396	func wrapDockerInfoErr(err error) error {
397		if err == nil {
398			return nil
399		}
400		lower := strings.ToLower(err.Error())
401		switch {
402		case strings.Contains(lower, "permission denied") && strings.Contains(lower, "docker.sock"):
403			return fmt.Errorf("cannot access Docker socket (add the SSH user to the 'docker' group and reconnect SSH, or use root): %w", err)
404		case strings.Contains(lower, "permission denied"):
405			return fmt.Errorf("permission denied talking to Docker: %w", err)
406		case strings.Contains(lower, "cannot connect to the docker daemon"),
407			strings.Contains(lower, "is the docker daemon running"),
408			strings.Contains(lower, "connection refused"):
409			return fmt.Errorf("Docker daemon not reachable (start the Docker service, e.g. systemctl start docker; see README): %w", err)
410		default:
411			return err
412		}
413	}
414	
415	// UnixDockerServerVersion returns the Docker Engine server version from docker info, or an error
416	// that distinguishes socket permissions and daemon reachability from other failures.
417	func UnixDockerServerVersion(h *host.Host) (string, error) {
418		out, err := h.Run(prependDarwinDockerPATH(h, "docker info --format '{{.ServerVersion}}'"))
419		out = strings.TrimSpace(out)
420		if err == nil {
421			if out == "" {
422				return "", fmt.Errorf("docker info returned empty server version")
423			}
424			return out, nil
425		}
426		return "", wrapDockerInfoErr(err)
427	}
